type stepMsg agent.StepResult
type errMsg error
type logMsg string

type model struct {
	agent           *agent.Agent
	state           string
	prevState       string
	history         []string
	systemLogs      []string
	viewport        viewport.Model
	logViewport     viewport.Model
	textInput       textinput.Model
	searchInput     textinput.Model
	spinner         spinner.Model
	glamourRenderer *glamour.TermRenderer
	lastTask        string
	statePath       string
	systemPrompt    string
